return [{ json: { ...item, config } }];

const item = $input.first().json;
const nodeScript = "const fs=require('fs'); const path=require('path'); const {spawnSync}=require('child_process'); const [prompt,model,conversationId]=process.argv.slice(1); const safeConversationId=(conversationId||'reply').replace(/[^a-zA-Z0-9_-]/g,'_'); const artifactDir='/home/node/.n8n/ghost-artifacts'; fs.mkdirSync(artifactDir,{recursive:true}); const timestamp=new Date().toISOString().replace(/[-:]/g,'').replace(/\\.\\d{3}Z$/,'Z'); const basePath=path.join(artifactDir,safeConversationId+'-'+timestamp); const replyPath=basePath+'.reply.txt'; const stdoutPath=basePath+'.stdout.txt'; const stderrPath=basePath+'.stderr.txt'; const summarize=value=>value.replace(/\\s+/g,' ').trim().slice(0,600); const cleanStderr=value=>{ const text=(value||'').replace(/\\r/g,''); if(!text.trim()) return ''; const lines=text.split('\\n').map(line=>line.trim()).filter(Boolean); const filtered=lines.filter(line=>{ if (/^OpenAI Codex v/i.test(line)) return false; if (/^[-]{4,}$/.test(line)) return false; if (/^(workdir|model|provider|approval|sandbox|reasoning effort|reasoning summaries|session id):/i.test(line)) return false; if (/^(user|assistant|system):?$/i.test(line)) return false; if (/^mcp startup:/i.test(line)) return false; if (/^tokens used$/i.test(line)) return false; if (/^[0-9][0-9,]*$/.test(line)) return false; if (/^system: You are Ghost/.test(line)) return false; return true; }); return summarize((filtered.length ? filtered : lines.slice(0,6)).join(' ')); }; let exitCode=127; let errorText=''; try{const result=spawnSync('/opt/ghost/bin/codex-safe',['exec','--skip-git-repo-check','--model',model,'--sandbox','workspace-write','-o',replyPath,prompt],{encoding:'utf8'}); exitCode=typeof result.status==='number'?result.status:127; fs.writeFileSync(stdoutPath,result.stdout||'','utf8'); fs.writeFileSync(stderrPath,result.stderr||'','utf8'); if(result.error){errorText=result.error.message||String(result.error); fs.appendFileSync(stderrPath,(result.stderr?'\\n':'')+errorText,'utf8')}}catch(error){errorText=error.message||String(error); fs.writeFileSync(stdoutPath,'','utf8'); fs.writeFileSync(stderrPath,errorText,'utf8')}; const reply=fs.existsSync(replyPath)?fs.readFileSync(replyPath,'utf8').trim():''; const stdoutText=fs.existsSync(stdoutPath)?fs.readFileSync(stdoutPath,'utf8'):''; const stderrText=fs.existsSync(stderrPath)?fs.readFileSync(stderrPath,'utf8'):errorText; const payload={reply,artifact_path:fs.existsSync(replyPath)?replyPath:'',stdout_path:fs.existsSync(stdoutPath)?stdoutPath:'',stderr_path:fs.existsSync(stderrPath)?stderrPath:'',success:exitCode===0&&reply.length>0,command_exit_code:exitCode,stdout_summary:summarize(stdoutText),stderr_summary:cleanStderr(stderrText)}; process.stdout.write(JSON.stringify(payload))";
const model = item.selected_model || item.config?.codex?.model_alias || 'gpt-5.4';
const conversationId = item.conversation_id || 'reply';
const prompt = item.prompt || '';
const codexCommand = [
  'node',
  '-e',
  JSON.stringify(nodeScript),
  JSON.stringify(prompt),
  JSON.stringify(model),
  JSON.stringify(conversationId),
].join(' ');
return [{ json: { ...item, codex_command: codexCommand } }];

const result = $input.first().json;
const context = $('Expose Route Metadata').item.json;
const rawStdout = typeof result.stdout === 'string' ? result.stdout.trim() : '';
const nodeError = typeof result.error === 'string' ? result.error : (result.error?.message || '');
let payload = {};
if (rawStdout) {
  try {
    payload = JSON.parse(rawStdout);
  } catch (error) {
    payload = {
      reply: rawStdout,
      success: true,
      command_exit_code: 0,
      stdout_summary: rawStdout.slice(0, 600),
      stderr_summary: typeof result.stderr === 'string' ? result.stderr.trim().slice(0, 600) : '',
      artifact_path: '',
    };
  }
}
const stderrSummary = payload.stderr_summary || (typeof result.stderr === 'string' ? result.stderr.trim().slice(0, 600) : '') || nodeError.slice(0, 600);
const commandExitCode = payload.command_exit_code ?? (nodeError ? 127 : null);
const commandSuccess = Boolean(payload.success);
const failureSuffix = commandExitCode !== undefined && commandExitCode !== null ? ` (exit ${commandExitCode})` : '';
const failureReason = stderrSummary || 'No additional stderr was captured.';
const reply = (payload.reply || '').trim() || (commandSuccess ? '[no-codex-reply]' : `Codex execution failed${failureSuffix}. ${failureReason}`);
return [{ json: {
  ...context,
  ...result,
  codex_raw_result: payload,
  conversation_id: context.conversation_id || '',
  reply,
  provider_used: context.provider || '',
  model_used: context.selected_model || '',
  task_class: context.task_class || '',
  approval_required: context.approval_required || false,
  risk_level: context.risk_level || 'safe',
  risk_reasons: context.risk_reasons || [],
  risk_codes: context.risk_codes || [],
  task_summary: context.task_summary || '',
  command_success: commandSuccess,
  command_exit_code: commandExitCode,
  stdout_summary: payload.stdout_summary || '',
  stderr_summary: stderrSummary,
  artifact_path: payload.artifact_path || '',
  codex_command_status: commandSuccess ? 'succeeded' : 'failed',
  error_type: commandSuccess ? '' : 'codex_command_failed',
} }];

const context = $input.first().json;
const reasons = Array.isArray(context.risk_reasons) && context.risk_reasons.length
  ? context.risk_reasons.join(' ')
  : 'Risk policy requires review.';
const reply = `Approval required before Codex execution. Risk level: ${context.risk_level || 'unknown'}. ${reasons}`;
return [{ json: {
  ...context,
  reply,
  provider_used: context.provider || '',
  model_used: context.selected_model || '',
  task_class: context.task_class || '',
  command_success: false,
  error_type: 'approval_required',
  codex_command_status: 'blocked_pending_approval',
  artifact_path: '',
  stdout_summary: '',
  stderr_summary: reasons,
  command_exit_code: null,
} }];

const item = $input.first().json;
const priority = { decision: 0, environment_fact: 1, operational_note: 2, task_summary: 3, conversation_summary: 4 };
const normalizeWhitespace = (value) => String(value || '').replace(/\s+/g, ' ').trim();
const normalizeKey = (entry) => `${entry.memory_type}|${entry.scope}|${normalizeWhitespace(entry.summary).toLowerCase()}`;
const compactSummary = (entry) => {
  const limit = entry.memory_type === 'task_summary' || entry.memory_type === 'conversation_summary' ? 160 : 190;
  return normalizeWhitespace(entry.summary).slice(0, limit);
};
const memoryItems = $items('Load Ghost Memory')
  .map((entry) => entry.json || {})
  .filter((entry) => !entry.error && entry.memory_type && entry.summary && entry.scope)
  .map((entry) => ({
    scope: String(entry.scope).trim(),
    memory_type: String(entry.memory_type).trim(),
    importance: Number.isFinite(Number(entry.importance)) ? Number(entry.importance) : 3,
    summary: compactSummary(entry),
  }))
  .filter((entry) => entry.summary)
  .sort((a, b) => {
    const scopeDiff = (a.scope === 'conversation' ? 0 : 1) - (b.scope === 'conversation' ? 0 : 1);
    if (scopeDiff !== 0) return scopeDiff;
    const typeDiff = (priority[a.memory_type] ?? 9) - (priority[b.memory_type] ?? 9);
    if (typeDiff !== 0) return typeDiff;
    return (b.importance || 0) - (a.importance || 0);
  });
const seen = new Set();
const filteredMemoryItems = [];
for (const entry of memoryItems) {
  const key = normalizeKey(entry);
  if (!key || seen.has(key)) continue;
  seen.add(key);
  filteredMemoryItems.push(entry);
  if (filteredMemoryItems.length >= 6) break;
}
const ghostMemoryBlock = filteredMemoryItems.length
  ? 'Ghost memory:\n' + filteredMemoryItems.map((entry) => `- [${entry.memory_type}][${entry.scope}] ${entry.summary}`).join('\n')
  : '';
const systemPrompt = ghostMemoryBlock
  ? `${item.system_prompt}\nUse Ghost memory only when it is directly relevant. Prefer conversation memory over global memory when both exist.\n\n${ghostMemoryBlock}`
  : item.system_prompt;

return [{ json: {
  ...item,
  ghost_memory_items: filteredMemoryItems,
  ghost_memory_block: ghostMemoryBlock,
  system_prompt: systemPrompt,
} }];

const savedMessage = $input.first().json;
const routeContext = $('Expose Route Metadata').item.json;
const replyContext = $('Build API Response').item.json;
const messages = Array.isArray(routeContext.messages) ? routeContext.messages : [];
const lastUser = [...messages].reverse().find((message) => message.role === 'user');
const latestUserMessage = (lastUser?.content || '').trim();
const assistantReply = (replyContext.reply || '').trim();
const memoryTestMode = $('Normalize Input').item.json.memory_test_mode || '';
const taskClass = replyContext.task_class || 'chat';
const meaningfulTechnicalWork = taskClass === 'technical_work'
  && replyContext.command_success === true
  && /(implement|implemented|fix|fixed|update|updated|patch|patched|migrate|migration|refactor|created|added|write|wrote|build|built)/i.test(`${latestUserMessage} ${assistantReply}`)
  && assistantReply.length >= 24;
const explicitMemoryCue = /(decision|architectural decision|architecture decision|environment fact|runtime fact|operational note|runtime note|user preference|durable preference|remember this|preference|for future responses|always|never)/i.test(latestUserMessage);
const shouldExtractMemory = Boolean(savedMessage.id && assistantReply)
  && !replyContext.approval_required
  && replyContext.error_type !== 'approval_required'
  && (taskClass !== 'technical_work' || replyContext.command_success !== false)
  && (explicitMemoryCue || meaningfulTechnicalWork || assistantReply.length >= 40);
const extractionContract = {
  items: [
    {
      scope: 'global|conversation|task',
      memory_type: 'task_summary|decision|environment_fact|operational_note|conversation_summary',
      title: 'short title or empty string',
      summary: 'durable compact summary',
      details_json: {},
      importance: 1,
    },
  ],
};
const extractionPrompt = [
  'You extract durable structured Ghost memory.',
  'Return JSON only. No markdown. No explanation. No surrounding prose.',
  'Return exactly one object with one key: items.',
  'If nothing qualifies, return {"items":[]}.',
  'Each item must contain exactly these keys: scope, memory_type, title, summary, details_json, importance.',
  'Allowed scope: global, conversation, task.',
  'Allowed memory_type: task_summary, decision, environment_fact, operational_note, conversation_summary.',
  'importance must be an integer 1..5.',
  'title should be short. summary should be compact, durable, and under 240 characters.',
  'details_json must be a small object. Use {} when not needed.',
  'Do not store chit-chat, greetings, vague acknowledgements, raw runtime noise, stack traces, banners, code fences, or duplicate restatements.',
  'Prefer decision, environment_fact, operational_note over weak summaries.',
  'Only emit task_summary when meaningful work completed successfully.',
  'Return at most 3 items.',
  '',
  'JSON schema shape:',
  JSON.stringify(extractionContract),
  '',
  'Turn context JSON:',
  JSON.stringify({
    task_class: taskClass,
    provider_used: replyContext.provider_used || '',
    model_used: replyContext.model_used || '',
    command_success: replyContext.command_success,
    risk_level: replyContext.risk_level || 'safe',
    meaningful_technical_work: meaningfulTechnicalWork,
    latest_user_message: latestUserMessage,
    assistant_reply: assistantReply,
  }),
].join('\n');

return [{ json: {
  conversation_id: replyContext.conversation_id || '',
  source_message_id: savedMessage.id || '',
  task_class: taskClass,
  latest_user_message: latestUserMessage,
  assistant_reply: assistantReply,
  memory_test_mode: memoryTestMode,
  should_extract_memory: shouldExtractMemory,
  meaningful_technical_work: meaningfulTechnicalWork,
  extraction_prompt: extractionPrompt,
  memory_debug: {
    extractor_attempted: shouldExtractMemory,
    extractor_skipped: !shouldExtractMemory,
    fallback_used: false,
    candidate_count: 0,
    filtered_count: 0,
    saved_count: 0,
  },
} }];

const response = $input.first().json;
const context = $('Build Memory Extraction Input').item.json;
const allowedScopes = new Set(['global', 'conversation', 'task']);
const allowedTypes = new Set(['task_summary', 'decision', 'environment_fact', 'operational_note', 'conversation_summary']);
const parseOutputText = () => {
  if (typeof response.output_text === 'string' && response.output_text.trim()) return response.output_text.trim();
  if (Array.isArray(response.output)) {
    const text = response.output
      .flatMap((entry) => Array.isArray(entry.content) ? entry.content : [])
      .map((entry) => entry.text || entry.value || '')
      .join('')
      .trim();
    if (text) return text;
  }
  if (typeof response.response === 'string' && response.response.trim()) return response.response.trim();
  return '';
};
const extractJsonText = (text) => {
  if (!text) return '';
  const trimmed = text.trim();
  if (trimmed.startsWith('{') && trimmed.endsWith('}')) return trimmed;
  const start = trimmed.indexOf('{');
  const end = trimmed.lastIndexOf('}');
  return start >= 0 && end > start ? trimmed.slice(start, end + 1) : trimmed;
};
const sanitizeItem = (entry) => ({
  scope: String(entry.scope || '').trim(),
  memory_type: String(entry.memory_type || '').trim(),
  title: entry.title ? String(entry.title).replace(/\s+/g, ' ').trim().slice(0, 160) : '',
  summary: String(entry.summary || '').replace(/\s+/g, ' ').trim().slice(0, 240),
  details_json: entry.details_json && typeof entry.details_json === 'object' && !Array.isArray(entry.details_json) ? entry.details_json : {},
  importance: Number.isFinite(Number(entry.importance)) ? Math.max(1, Math.min(5, Math.round(Number(entry.importance)))) : 3,
});
const hasNoisySummary = (summary) => /```|stack trace|exception:|error:|stderr|stdout|traceback|OpenAI Codex|session id:|tokens used|^hi$|^hello$|^thanks$|^ok$|^okay$|^understood$/i.test(summary);
const normalizedKey = (entry) => `${entry.scope}|${entry.memory_type}|${entry.summary.toLowerCase()}`;
const buildFallbackItems = () => {
  if (context.memory_test_mode === 'invalid_json') return [];
  const userText = String(context.latest_user_message || '').trim();
  const normalizedUser = userText.replace(/\s+/g, ' ').trim();
  const fallbackItems = [];
  const pushFallback = (entry) => fallbackItems.push(entry);
  const preferenceMatch = normalizedUser.match(/(?:user preference(?: for this conversation)?|durable preference|preference|instruction|remember this|for future responses)\s*:\s*(.+)$/i);
  if (preferenceMatch?.[1] && /(always|never|prefer|prefers|avoid|use|do not|don't|keep|concise|verbose|full config files|snippets)/i.test(preferenceMatch[1])) {
    pushFallback({
      scope: 'conversation',
      memory_type: 'decision',
      title: 'Durable preference',
      summary: preferenceMatch[1],
      details_json: { source: 'heuristic_fallback', trigger: 'explicit_preference' },
      importance: 4,
    });
  }
  const prefersSentence = normalizedUser.match(/(the user prefers .+?)(?:\.\s*(remember this preference|remember this|save this preference))?$/i);
  if (prefersSentence?.[1] && /(prefers|avoid|use|do not|don't)/i.test(prefersSentence[1])) {
    pushFallback({
      scope: 'conversation',
      memory_type: 'decision',
      title: 'Durable preference',
      summary: prefersSentence[1],
      details_json: { source: 'heuristic_fallback', trigger: 'preference_sentence' },
      importance: 4,
    });
  }
  const architectureMatch = normalizedUser.match(/(?:architectural decision|architecture decision|decision(?: for this conversation)?)\s*:\s*(.+)$/i);
  if (architectureMatch?.[1] && /(use|prefer|keep|avoid|do not|don't)/i.test(architectureMatch[1])) {
    pushFallback({
      scope: 'conversation',
      memory_type: 'decision',
      title: 'Architectural decision',
      summary: architectureMatch[1],
      details_json: { source: 'heuristic_fallback', trigger: 'explicit_decision' },
      importance: 5,
    });
  }
  const envFactMatch = normalizedUser.match(/(?:environment fact|runtime fact)\s*:\s*(.+)$/i);
  if (envFactMatch?.[1] && envFactMatch[1].length >= 16) {
    pushFallback({
      scope: 'conversation',
      memory_type: 'environment_fact',
      title: 'Environment fact',
      summary: envFactMatch[1],
      details_json: { source: 'heuristic_fallback', trigger: 'explicit_fact' },
      importance: 4,
    });
  }
  const operationalNoteMatch = normalizedUser.match(/(?:operational note|runtime note)\s*:\s*(.+)$/i);
  if (operationalNoteMatch?.[1] && operationalNoteMatch[1].length >= 16) {
    pushFallback({
      scope: 'conversation',
      memory_type: 'operational_note',
